            String endDateStr = e.getFieldValue(endDateDomainId);
            Date startDate = null, endDate = null;
            long timeDiff = (long)-1;
            
            if (startDateStr.matches("^\\d+/\\d+/\\d+$")) {
                startDate = Encoder.parseDate(startDateStr, "yyyy/MM/dd");
            }
            else if (startDateStr.matches("^\\d+/\\d+/\\d+ \\d+:\\d+:\\d+$")) {
                startDate = Encoder.parseDate(startDateStr, "yyyy/MM/dd HH:mm:ss");
            }
            if (endDateStr.matches("^\\d+/\\d+/\\d+$")) {
                endDate = Encoder.parseDate(endDateStr, "yyyy/MM/dd");
                //add 1 day if format of end date is yyyy/MM/dd
                if (endDate != null) {
                    Calendar c = Calendar.getInstance(); 
                    c.setTime(endDate); 
                    c.add(Calendar.DATE, 1);
                    endDate = c.getTime();
                }
            }
            else if (endDateStr.matches("^\\d+/\\d+/\\d+ \\d+:\\d+:\\d+$")) {
                endDate = Encoder.parseDate(endDateStr, "yyyy/MM/dd HH:mm:ss");
            }
            
            if (startDate == null && endDate == null) {
                invalidEntryCount++;
                continue;
            }
            else if (startDate != null && endDate != null && endDate.before(startDate)) {
                invalidEntryCount++;
                continue; 
            }
            
            label = formatValueByCellAttr(label, labelInfo, apname, bundle);
